+//! Real-world batched Metal MoE test with actual Mixtral Q8_0 weights
+//! This loads weights from a GGUF file to test with real memory bandwidth bottleneck
+//! Run: zig build test-batched-moe-real -- <path-to-mixtral-Q8_0.gguf>
+
+const std = @import("std");
+const moe_metal = @import("moe_metal.zig");
+const moe = @import("moe.zig");
+const gguf_loader = @import("inference/gguf_loader.zig");
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    // Get model path from arguments
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    if (args.len < 2) {
+        std.debug.print("Usage: {s} <model.gguf>\n", .{args[0]});
+        std.debug.print("Example: {s} models/mixtral-8x7b-Q8_0.gguf\n", .{args[0]});
+        return error.MissingArgument;
+    }
+
+    const model_path = args[1];
+
+    std.debug.print("\n🔬 Real Batched Metal MoE Performance Test\n", .{});
+    std.debug.print("=====================================\n\n", .{});
+    std.debug.print("Model: {s}\n\n", .{model_path});
+
+    // Load GGUF file
+    std.debug.print("📦 Loading GGUF model...\n", .{});
+    var loader = try gguf_loader.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+
+    std.debug.print("  Tensors: {}\n\n", .{loader.tensor_count});
+
+    // Initialize Metal engine
+    std.debug.print("⚙️  Initializing Metal GPU engine...\n", .{});
+    var engine = try moe_metal.MetalMoEEngine.init(allocator);
+    defer engine.deinit();
+
+    std.debug.print("✅ Metal engine initialized\n\n", .{});
+
+    // Mixtral config
+    const n_embd: u32 = 4096;
+    const n_expert: u32 = 8;
+    const n_ff: u32 = 14336;
+
+    // Load MoE weights for layer 0
+    std.debug.print("📥 Loading MoE weights for layer 0...\n", .{});
+    var layer_weights = try moe.loadMoELayerWeights(
+        allocator,
+        &loader,
+        0, // First layer
+        n_expert,
+    );
+    defer layer_weights.deinit();
+
+    std.debug.print("  Router: {} bytes\n", .{layer_weights.router_weights.len});
+    std.debug.print("  Expert 0 gate: {} bytes\n", .{layer_weights.expert_gate_weights[0].len});
+    std.debug.print("  Expert 0 up: {} bytes\n", .{layer_weights.expert_up_weights[0].len});
+    std.debug.print("  Expert 0 down: {} bytes\n\n", .{layer_weights.expert_down_weights[0].len});
+
+    // Create random input (single token)
+    const single_input = try allocator.alloc(f32, n_embd);
+    defer allocator.free(single_input);
+
+    var prng = std.Random.DefaultPrng.init(42);
+    const random = prng.random();
+    for (single_input) |*val| {
+        val.* = random.float(f32) * 2.0 - 1.0;
+    }
+
+    // Convert expert weights to arrays
+    var expert_gate: [8][]const u8 = undefined;
+    var expert_up: [8][]const u8 = undefined;
+    var expert_down: [8][]const u8 = undefined;
+    for (0..8) |i| {
+        expert_gate[i] = layer_weights.expert_gate_weights[i];
+        expert_up[i] = layer_weights.expert_up_weights[i];
+        expert_down[i] = layer_weights.expert_down_weights[i];
+    }
+
+    std.debug.print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n", .{});
+    std.debug.print("Test 1: Single Token (Baseline)\n", .{});
+    std.debug.print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n", .{});
+
+    // Warmup
+    {
+        std.debug.print("Warming up GPU...\n", .{});
+        const warmup_result = try engine.moeFFN_Q8(
+            allocator,
+            single_input,
+            layer_weights.router_weights,
+            expert_gate,
+            expert_up,
+            expert_down,
+            n_expert,
+            n_embd,
+            n_ff,
+        );
+        defer allocator.free(warmup_result);
+    }
+
+    std.debug.print("Warmup complete. Running 10 iterations...\n\n", .{});
+
+    // Benchmark: 10 single tokens (sequential)
+    const single_start = std.time.milliTimestamp();
+
+    for (0..10) |_| {
+        const result = try engine.moeFFN_Q8(
+            allocator,
+            single_input,
+            layer_weights.router_weights,
+            expert_gate,
+            expert_up,
+            expert_down,
+            n_expert,
+            n_embd,
+            n_ff,
+        );
+        allocator.free(result);
+    }
+    const single_time = std.time.milliTimestamp() - single_start;
+
+    std.debug.print("✅ Single token x10: {d} ms\n", .{single_time});
+    std.debug.print("   Per token: {d:.1} ms\n\n", .{@as(f64, @floatFromInt(single_time)) / 10.0});
+
+    std.debug.print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n", .{});
+    std.debug.print("Test 2: Batched 10 Tokens (Parallel)\n", .{});
+    std.debug.print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n", .{});
+
+    // Create batch input (10 tokens)
+    const batch_size: u32 = 10;
+    var batch_input = try allocator.alloc(f32, batch_size * n_embd);
+    defer allocator.free(batch_input);
+
+    // Fill batch with 10 different random vectors
+    for (0..batch_size) |i| {
+        for (0..n_embd) |j| {
+            batch_input[i * n_embd + j] = random.float(f32) * 2.0 - 1.0;
+        }
+    }
+
+    std.debug.print("Running batched inference...\n\n", .{});
+
+    // Benchmark: 10 tokens in one batch
+    const batch_start = std.time.milliTimestamp();
+    const batch_result = try engine.moeFFN_Q8_Batched(
+        allocator,
+        batch_input,
+        batch_size,
+        layer_weights.router_weights,
+        expert_gate,
+        expert_up,
+        expert_down,
+        n_expert,
+        n_embd,
+        n_ff,
+    );
+    defer allocator.free(batch_result);
+    const batch_time = std.time.milliTimestamp() - batch_start;
+
+    std.debug.print("✅ Batched 10 tokens: {d} ms\n", .{batch_time});
+    std.debug.print("   Per token (amortized): {d:.1} ms\n\n", .{@as(f64, @floatFromInt(batch_time)) / 10.0});
+
+    std.debug.print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n", .{});
+    std.debug.print("Results\n", .{});
+    std.debug.print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n", .{});
+
+    const speedup = @as(f64, @floatFromInt(single_time)) / @as(f64, @floatFromInt(batch_time));
+
+    std.debug.print("Single token x10:    {d:>6} ms ({d:.1} ms/token)\n", .{ single_time, @as(f64, @floatFromInt(single_time)) / 10.0 });
+    std.debug.print("Batched 10 tokens:   {d:>6} ms ({d:.1} ms/token)\n", .{ batch_time, @as(f64, @floatFromInt(batch_time)) / 10.0 });
+    std.debug.print("\n🚀 SPEEDUP: {d:.1}x\n\n", .{speedup});
+
+    if (speedup >= 8.0) {
+        std.debug.print("✅ SUCCESS! Achieved 8x+ speedup (expected 8-10x)\n", .{});
+    } else if (speedup >= 5.0) {
+        std.debug.print("⚠️  PARTIAL SUCCESS: {d:.1}x speedup (expected 8-10x)\n", .{speedup});
+        std.debug.print("   This is still good! Memory bandwidth savings are working.\n", .{});
+    } else {
+        std.debug.print("❌ UNEXPECTED: Only {d:.1}x speedup (expected 8-10x)\n", .{speedup});
+        std.debug.print("   Possible issues:\n", .{});
+        std.debug.print("   - Weight caching not working\n", .{});
+        std.debug.print("   - Batch dispatch not parallelizing\n", .{});
+    }
+
+    std.debug.print("\n💡 For full 32-layer Mixtral inference:\n", .{});
+    const single_per_token = @as(f64, @floatFromInt(single_time)) / 10.0;
+    const batch_per_token = @as(f64, @floatFromInt(batch_time)) / 10.0;
+    const single_total = single_per_token * 32.0;
+    const batch_total = batch_per_token * 32.0;
+
+    std.debug.print("   Single: {d:.1}ms/token × 32 layers = {d:.2}s/token = {d:.2} tok/s\n", .{ single_per_token, single_total / 1000.0, 1000.0 / single_total });
+    std.debug.print("   Batched: {d:.1}ms/token × 32 layers = {d:.2}s/token = {d:.2} tok/s\n", .{ batch_per_token, batch_total / 1000.0, 1000.0 / batch_total });
+
+    // Physics limit analysis
+    std.debug.print("\n📊 SSD Bandwidth Analysis:\n", .{});
+    std.debug.print("   Data loaded per token (Q8): ~13 GB\n", .{});
+    std.debug.print("   SSD bandwidth: ~6 GB/s\n", .{});
+    std.debug.print("   Theoretical limit: 13GB / 6GB/s = 2.1s per token (single)\n", .{});
+    std.debug.print("   Batched (10 tok): 2.1s / 10 = 0.21s per token = 4.7 tok/s\n", .{});
+    std.debug.print("\n💡 To reach ~9 tok/s: Implement Q4_0 kernels (halves data size)\n", .{});
+    std.debug.print("\n", .{});
+}
